<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';use VP3\Sales\ProposalService;$admin=vp3_require_admin_permission('sales.manage');$id=(int)vp3_input('id');$leadId=(int)vp3_input('lead_id');$service=new ProposalService(vp3_db());$row=null;if($id){$s=vp3_db()->prepare('SELECT * FROM proposals WHERE id=?');$s->execute([$id]);$row=$s->fetch();if(!$row){http_response_code(404);exit('Proposal not found.');}}
if(vp3_method()==='POST'){vp3_verify_csrf();$action=vp3_input('action','create');try{if($action==='create'){$items=[];$names=(array)($_POST['item_name']??[]);foreach($names as $i=>$name){if(trim((string)$name)==='')continue;$items[]=['name'=>$name,'description'=>$_POST['item_description'][$i]??'','quantity'=>$_POST['item_quantity'][$i]??1,'unit_price_cents'=>$_POST['item_unit_price'][$i]??0,'billing_type'=>$_POST['item_billing'][$i]??'one_time','item_type'=>'service'];}$created=$service->create(['lead_id'=>vp3_input('lead_id'),'customer_id'=>vp3_input('customer_id'),'title'=>vp3_input('title'),'summary'=>vp3_input('summary'),'scope_text'=>vp3_input('scope_text'),'terms_text'=>vp3_input('terms_text'),'currency'=>vp3_input('currency','USD'),'discount_cents'=>vp3_input('discount_cents','0'),'tax_cents'=>vp3_input('tax_cents','0'),'deposit_cents'=>vp3_input('deposit_cents','0'),'valid_until'=>vp3_input('valid_until')],$items,(int)$admin['id']);$id=(int)$created['id'];}elseif($action==='status'){$service->updateStatus($id,vp3_input('status'),(int)$admin['id']);}elseif($action==='item'&&$id){$qty=max(.01,(float)vp3_input('quantity','1'));$unit=max(0,(int)vp3_input('unit_price_cents','0'));$name=vp3_text_slice(vp3_input('name'),190);if($name==='')throw new RuntimeException('item_name_required');$itemType=in_array(vp3_input('item_type'),['package','service','license','hosting','deposit','discount','custom'],true)?vp3_input('item_type'):'service';$billing=in_array(vp3_input('billing_type'),['one_time','monthly','yearly','custom'],true)?vp3_input('billing_type'):'one_time';$packageId=(int)vp3_input('service_package_id');if($packageId>0){$package=vp3_db()->prepare("SELECT COUNT(*) FROM service_packages WHERE id=? AND status='active'");$package->execute([$packageId]);if((int)$package->fetchColumn()<1)throw new RuntimeException('service_package_not_available');}vp3_db()->prepare('INSERT INTO proposal_items(proposal_id,service_package_id,item_type,name,description,quantity,unit_price_cents,total_cents,billing_type,sort_order,created_at,updated_at) VALUES (?,NULLIF(?,0),?,?,?,?,?,?,?, ?,NOW(),NOW())')->execute([$id,$packageId,$itemType,$name,vp3_input('description'),$qty,$unit,(int)round($qty*$unit),$billing,(int)vp3_input('sort_order','0')]);$service->recalculate($id);}elseif($action==='activate_project'&&$id){$proposal=vp3_db()->prepare("SELECT * FROM proposals WHERE id=? AND status='accepted' AND customer_id IS NOT NULL");$proposal->execute([$id]);$proposal=$proposal->fetch();if(!$proposal)throw new RuntimeException('accepted_customer_proposal_required');$existing=vp3_db()->prepare('SELECT id FROM creative_projects WHERE proposal_id=?');$existing->execute([$id]);if($existing->fetchColumn())throw new RuntimeException('project_already_exists');$project=(new VP3\Projects\ProjectService(vp3_db()))->create(['customer_id'=>$proposal['customer_id'],'proposal_id'=>$id,'title'=>$proposal['title'],'summary'=>$proposal['summary'],'phase'=>'discovery','status'=>'active'],(int)$admin['id']);vp3_flash('success','Project activated.');vp3_redirect('admin/project.php?id='.$project['id']);}vp3_flash('success','Proposal updated.');}catch(Throwable $e){vp3_flash('error',str_replace('_',' ',$e->getMessage()));}vp3_redirect('admin/proposal.php?id='.$id);}
$leads=vp3_db()->query("SELECT id,name,email,project_name FROM leads WHERE stage NOT IN ('lost','archived') ORDER BY updated_at DESC LIMIT 250")->fetchAll();$customers=vp3_db()->query("SELECT id,name,email FROM customers WHERE status IN ('active','pending') ORDER BY name")->fetchAll();$packages=[];try{$packages=vp3_db()->query("SELECT id,name,price_cents,billing_type FROM service_packages WHERE status='active' ORDER BY featured_rank DESC,name")->fetchAll();}catch(Throwable){}$items=$acceptance=[];if($id){$s=vp3_db()->prepare('SELECT * FROM proposal_items WHERE proposal_id=? ORDER BY sort_order,id');$s->execute([$id]);$items=$s->fetchAll();$s=vp3_db()->prepare('SELECT * FROM proposal_acceptances WHERE proposal_id=?');$s->execute([$id]);$acceptance=$s->fetch()?:[];$s=vp3_db()->prepare('SELECT * FROM proposals WHERE id=?');$s->execute([$id]);$row=$s->fetch();}$pageTitle=$row?'Proposal · '.$row['proposal_number']:'Create Proposal';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Proposal builder</span><h1><?=vp3_e($pageTitle)?></h1></div><a class="button secondary" href="proposals.php">Back</a></div><?php if(!$id):?><form class="card admin-form" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="create"><div class="admin-form-grid"><div class="field"><label>Lead</label><select name="lead_id"><option value="0">None</option><?php foreach($leads as $l):?><option value="<?=(int)$l['id']?>" <?=($leadId===(int)$l['id'])?'selected':''?>><?=vp3_e($l['name'].' · '.($l['project_name']?:$l['email']))?></option><?php endforeach;?></select></div><div class="field"><label>Customer</label><select name="customer_id"><option value="0">None</option><?php foreach($customers as $c):?><option value="<?=(int)$c['id']?>"><?=vp3_e($c['name'].' · '.$c['email'])?></option><?php endforeach;?></select></div><div class="field full"><label>Title</label><input name="title" required></div><div class="field full"><label>Summary</label><textarea name="summary"></textarea></div><div class="field full"><label>Scope</label><textarea name="scope_text"></textarea></div><div class="field full"><label>Terms</label><textarea name="terms_text">Scope changes require written approval. Payment, delivery, ownership, third-party services, and launch timing remain subject to the final agreed proposal.</textarea></div><div class="field"><label>Currency</label><input name="currency" value="USD" maxlength="3"></div><div class="field"><label>Valid until</label><input name="valid_until" type="date"></div><div class="field"><label>Discount cents</label><input name="discount_cents" type="number" min="0" value="0"></div><div class="field"><label>Tax cents</label><input name="tax_cents" type="number" min="0" value="0"></div><div class="field"><label>Deposit cents</label><input name="deposit_cents" type="number" min="0" value="0"></div></div><h3>Initial line items</h3><div class="proposal-item-builder"><?php for(