="hidden" name="action" value="item"><h3>Add line item</h3><div class="field"><label>Package</label><select name="service_package_id"><option value="0">Custom</option><?php foreach($packages as $p):?><option value="<?=(int)$p['id']?>"><?=vp3_e($p['name'])?></option><?php endforeach;?></select></div><div class="field"><label>Name</label><input name="name" required></div><div class="field"><label>Description</label><textarea name="description"></textarea></div><div class="field"><label>Quantity</label><input name="quantity" type="number" step="0.01" value="1"></div><div class="field"><label>Unit price cents</label><input name="unit_price_cents" type="number" value="0"></div><div class="field"><label>Billing</label><select name="billing_type"><option>one_time</option><option>monthly</option><option>yearly</option><option>custom</option></select></div><button class="button small">Add item</button></form><?php if($row['status']==='accepted'):?><form class="card admin-section" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="activate_project"><h3>Activate project</h3><p>Create the customer workspace from this accepted proposal.</p><button class="button">Create project</button></form><?php endif;?><?php if($acceptance):?><article class="card admin-section"><h3>Acceptance record</h3><p><?=vp3_e($acceptance['accepted_name'].' · '.$acceptance['accepted_email'])?></p><small><?=vp3_e($acceptance['accepted_at'].' · terms '.$acceptance['terms_version'])?></small></article><?php endif;?></aside></div><?php endif;?>
